package store

import (
	"crypto/sha256"
	"database/sql"
	"fmt"
	"log/slog"
	"strings"

	_ "modernc.org/sqlite"
)

// Database wraps the SQLite connection.
type Database struct {
	Conn *sql.DB
}

// MLSIdentity holds the local MLS signing identity generated by the Rust engine.
// There is at most ONE row in the mls_identity table (id = 1).
type MLSIdentity struct {
	DisplayName       string
	PublicKey         []byte // raw Ed25519 public key bytes — send to Admin
	SigningKeyPrivate []byte // raw Ed25519 private key bytes — NEVER leave this machine
	Credential        []byte // UTF-8 display_name bytes (Phase 4: proper BasicCredential)
}

// StoredAuthBundle holds the InvitationBundle received from the Admin.
// There is at most ONE row in the auth_bundle table (id = 1).
type StoredAuthBundle struct {
	DisplayName    string
	PeerID         string // Libp2p PeerID — bound in token to prevent replay attacks
	PublicKey      []byte // must match MLSIdentity.PublicKey
	TokenIssuedAt  int64
	TokenExpiresAt int64
	TokenSignature []byte // Admin's Ed25519 signature over the token payload
	BootstrapAddr  string // Libp2p multiaddr of the Admin node — entry point to the network
	RootPublicKey  []byte // Root Admin public key — stored on first import (TOFU)
}

func InitDB(path string) (*Database, error) {
	db, err := sql.Open("sqlite", path)
	if err != nil {
		return nil, fmt.Errorf("failed to open database: %w", err)
	}
	// Keep a single writer connection in-process and wait on busy locks
	// to reduce SQLITE_BUSY under concurrent goroutines.
	db.SetMaxOpenConns(1)
	db.SetMaxIdleConns(1)

	if err := db.Ping(); err != nil {
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}
	if _, err := db.Exec(`PRAGMA journal_mode=WAL;`); err != nil {
		return nil, fmt.Errorf("set pragma journal_mode=WAL: %w", err)
	}
	if _, err := db.Exec(`PRAGMA busy_timeout=5000;`); err != nil {
		return nil, fmt.Errorf("set pragma busy_timeout: %w", err)
	}
	if _, err := db.Exec(`PRAGMA synchronous=NORMAL;`); err != nil {
		return nil, fmt.Errorf("set pragma synchronous: %w", err)
	}

	d := &Database{Conn: db}
	if err := d.createTables(); err != nil {
		return nil, err
	}

	slog.Info("Database initialized", "path", path)
	return d, nil
}

func (d *Database) createTables() error {
	queries := []string{
		// Legacy tables — kept for backward compatibility
		`CREATE TABLE IF NOT EXISTS users (
			id TEXT PRIMARY KEY,
			username TEXT NOT NULL,
			public_key BLOB,
			created_at DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,
		`CREATE TABLE IF NOT EXISTS messages (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			group_id TEXT NOT NULL,
			sender_id TEXT NOT NULL,
			content TEXT,
			mls_message BLOB,
			timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,

		// Generic key-value config store.
		// Used for: libp2p_priv_key, admin_root_private_key, etc.
		`CREATE TABLE IF NOT EXISTS system_config (
			key   TEXT PRIMARY KEY,
			value BLOB
		);`,

		// Local MLS signing identity (one row, id = 1).
		// Generated by Rust engine on first launch.
		// signing_key_private MUST never leave this machine.
		`CREATE TABLE IF NOT EXISTS mls_identity (
			id                  INTEGER PRIMARY KEY,
			display_name        TEXT    NOT NULL,
			public_key          BLOB    NOT NULL,
			signing_key_private BLOB    NOT NULL,
			credential          BLOB    NOT NULL,
			created_at          DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,

		// InvitationBundle received from the Admin (one row, id = 1).
		// Required before joining the P2P network.
		`CREATE TABLE IF NOT EXISTS auth_bundle (
			id               INTEGER PRIMARY KEY,
			display_name     TEXT    NOT NULL,
			peer_id          TEXT    NOT NULL DEFAULT '',
			public_key       BLOB    NOT NULL,
			token_issued_at  INTEGER NOT NULL,
			token_expires_at INTEGER NOT NULL,
			token_signature  BLOB    NOT NULL,
			bootstrap_addr   TEXT    NOT NULL,
			root_public_key  BLOB    NOT NULL,
			imported_at      DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,

		// Phase 4: MLS group state persisted by the Coordinator.
		`CREATE TABLE IF NOT EXISTS mls_groups (
			group_id         TEXT PRIMARY KEY,
			group_state      BLOB    NOT NULL,
			epoch            INTEGER NOT NULL DEFAULT 0,
			tree_hash        BLOB,
			my_role          TEXT    NOT NULL DEFAULT 'member',
			group_creator_peer_id TEXT NOT NULL DEFAULT '',
			lifecycle_status TEXT    NOT NULL DEFAULT 'active',
			left_at          INTEGER NOT NULL DEFAULT 0,
			group_type       TEXT    NOT NULL DEFAULT 'channel',
			dm_counterparty_peer_id TEXT NOT NULL DEFAULT '',
			category_id      TEXT    NOT NULL DEFAULT '',
			invite_policy    TEXT    NOT NULL DEFAULT 'creator_approval',
			created_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
			updated_at       DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,

		// Phase 4: coordination metadata per group.
		`CREATE TABLE IF NOT EXISTS coordination_state (
			group_id          TEXT PRIMARY KEY,
			active_view       TEXT NOT NULL DEFAULT '[]',
			token_holder      TEXT NOT NULL DEFAULT '',
			last_commit_hash  BLOB,
			last_commit_at    DATETIME,
			pending_proposals TEXT NOT NULL DEFAULT '[]',
			FOREIGN KEY (group_id) REFERENCES mls_groups(group_id)
		);`,

		// Phase 4: decrypted messages stored for UI display, ordered by HLC.
		`CREATE TABLE IF NOT EXISTS stored_messages (
			id               INTEGER PRIMARY KEY AUTOINCREMENT,
			group_id         TEXT    NOT NULL,
			epoch            INTEGER NOT NULL,
			sender_id        TEXT    NOT NULL,
			content          BLOB    NOT NULL,
			hlc_wall_time_ms INTEGER NOT NULL,
			hlc_counter      INTEGER NOT NULL,
			hlc_node_id      TEXT    NOT NULL,
			envelope_hash    BLOB
		);`,

		`CREATE INDEX IF NOT EXISTS idx_stored_messages_group_hlc
			ON stored_messages(group_id, hlc_wall_time_ms, hlc_counter, hlc_node_id);`,

		`CREATE INDEX IF NOT EXISTS idx_stored_messages_type
			ON stored_messages(json_extract(content, '$.type')) WHERE json_valid(content);`,
		`CREATE INDEX IF NOT EXISTS idx_stored_messages_post_id
			ON stored_messages(json_extract(content, '$.post_id')) WHERE json_valid(content);`,

		// Phase 7: Local directory caching PeerID -> Display Name.
		`CREATE TABLE IF NOT EXISTS local_profile (
			id                INTEGER PRIMARY KEY,
			peer_id           TEXT NOT NULL DEFAULT '',
			display_name      TEXT NOT NULL DEFAULT '',
			email             TEXT,
			phone             TEXT,
			avatar_hash       TEXT,
			avatar_mime       TEXT,
			avatar_updated_at INTEGER NOT NULL DEFAULT 0,
			profile_revision  INTEGER NOT NULL DEFAULT 0,
			updated_at        INTEGER NOT NULL DEFAULT (strftime('%s','now'))
		);`,
		`CREATE TABLE IF NOT EXISTS peer_directory (
			peer_id      TEXT PRIMARY KEY,
			display_name TEXT NOT NULL,
			updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,
		`CREATE TABLE IF NOT EXISTS avatar_blobs (
			hash         TEXT PRIMARY KEY,
			mime         TEXT NOT NULL,
			size         INTEGER NOT NULL,
			bytes        BLOB NOT NULL,
			created_at   INTEGER NOT NULL,
			last_used_at INTEGER NOT NULL
		);`,
		`CREATE TABLE IF NOT EXISTS group_members (
			group_id      TEXT    NOT NULL,
			peer_id       TEXT    NOT NULL,
			display_name  TEXT    NOT NULL DEFAULT '',
			role          TEXT    NOT NULL DEFAULT 'member',
			status        TEXT    NOT NULL DEFAULT 'active',
			source        TEXT    NOT NULL DEFAULT '',
			joined_at     INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			left_at       INTEGER NOT NULL DEFAULT 0,
			updated_at    INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (group_id, peer_id)
		);`,
		`CREATE INDEX IF NOT EXISTS idx_group_members_group_status
			ON group_members(group_id, status);`,
		`CREATE INDEX IF NOT EXISTS idx_group_members_peer
			ON group_members(peer_id);`,
		`CREATE TABLE IF NOT EXISTS channel_categories (
			category_id TEXT PRIMARY KEY,
			name        TEXT    NOT NULL,
			sort_order  INTEGER NOT NULL DEFAULT 0,
			created_by  TEXT    NOT NULL DEFAULT '',
			created_at  INTEGER NOT NULL,
			updated_at  INTEGER NOT NULL
		);`,
		`CREATE TABLE IF NOT EXISTS channel_category_sync_events (
			event_id   TEXT PRIMARY KEY,
			applied_at INTEGER NOT NULL
		);`,

		// Phase 5: local KeyPackage private bundles (one active per peer; reused after group join).
		// public_kp is used for invite distribution; private_bundle stays local forever.
		`CREATE TABLE IF NOT EXISTS kp_bundles (
			id              INTEGER PRIMARY KEY,
			peer_id         TEXT    NOT NULL UNIQUE,
			public_kp       BLOB    NOT NULL,
			private_bundle  BLOB    NOT NULL,
			created_at      DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,

		// Phase 5: outbound Welcome messages awaiting delivery (store-and-forward).
		// Creator side: written after AddMembers, deleted when invitee confirms join.
		`CREATE TABLE IF NOT EXISTS pending_welcomes_out (
			id              INTEGER PRIMARY KEY AUTOINCREMENT,
			target_peer_id  TEXT    NOT NULL,
			group_id        TEXT    NOT NULL,
			welcome_bytes   BLOB    NOT NULL,
			delivered       INTEGER NOT NULL DEFAULT 0,
			created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
			UNIQUE(target_peer_id, group_id)
		);`,

		// Phase 5.3: offline sync — MLS ciphertext envelopes (per-node monotonic seq).
		`CREATE TABLE IF NOT EXISTS envelope_log (
			id           INTEGER PRIMARY KEY AUTOINCREMENT,
			group_id     TEXT    NOT NULL,
			seq          INTEGER NOT NULL,
			msg_type     TEXT    NOT NULL,
			epoch        INTEGER NOT NULL,
			envelope     BLOB    NOT NULL,
			envelope_hash BLOB,
			source_path  TEXT    NOT NULL DEFAULT 'local',
			apply_state  TEXT    NOT NULL DEFAULT 'pending',
			last_apply_error TEXT NOT NULL DEFAULT '',
			last_apply_attempt_at INTEGER NOT NULL DEFAULT 0,
			applied_at   INTEGER NOT NULL DEFAULT 0,
			hlc_wall_ms  INTEGER NOT NULL,
			hlc_counter  INTEGER NOT NULL,
			hlc_node_id  TEXT    NOT NULL,
			created_at   INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			first_seen_at_ms INTEGER NOT NULL DEFAULT 0,
			received_at_ms INTEGER NOT NULL DEFAULT 0,
			UNIQUE(group_id, seq)
		);`,
		`CREATE INDEX IF NOT EXISTS idx_envelope_log_group_seq
			ON envelope_log(group_id, seq);`,
		`CREATE TABLE IF NOT EXISTS envelope_dedup (
			group_id      TEXT    NOT NULL,
			envelope_hash BLOB    NOT NULL,
			created_at    INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (group_id, envelope_hash)
		);`,
		`CREATE TABLE IF NOT EXISTS applied_envelopes (
			group_id      TEXT    NOT NULL,
			envelope_hash BLOB    NOT NULL,
			msg_type      TEXT    NOT NULL,
			epoch         INTEGER NOT NULL,
			applied_at    INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (group_id, envelope_hash)
		);`,

		`CREATE TABLE IF NOT EXISTS sync_acks (
			peer_id   TEXT    NOT NULL,
			group_id  TEXT    NOT NULL,
			acked_seq INTEGER NOT NULL DEFAULT 0,
			acked_at  INTEGER NOT NULL DEFAULT 0,
			PRIMARY KEY (peer_id, group_id)
		);`,

		`CREATE TABLE IF NOT EXISTS pending_delivery_acks (
			id             INTEGER PRIMARY KEY AUTOINCREMENT,
			target_peer_id TEXT    NOT NULL,
			group_id       TEXT    NOT NULL,
			acked_seq      INTEGER NOT NULL,
			created_at     INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			UNIQUE(target_peer_id, group_id)
		);`,

		`CREATE TABLE IF NOT EXISTS offline_sync_pull_state (
			group_id         TEXT NOT NULL,
			remote_peer_id   TEXT NOT NULL,
			last_remote_seq  INTEGER NOT NULL DEFAULT 0,
			updated_at       INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (group_id, remote_peer_id)
		);`,

		// Replicated invite assets stored by online peers (custom store protocol).
		`CREATE TABLE IF NOT EXISTS stored_keypackages (
			peer_id        TEXT PRIMARY KEY,
			public_kp      BLOB NOT NULL,
			source_peer_id TEXT NOT NULL,
			updated_at     INTEGER NOT NULL DEFAULT (strftime('%s','now'))
		);`,
		`CREATE TABLE IF NOT EXISTS stored_welcomes (
			invitee_peer_id TEXT NOT NULL,
			group_id        TEXT NOT NULL,
			group_type      TEXT NOT NULL DEFAULT 'channel',
			category_id     TEXT NOT NULL DEFAULT '',
			welcome_bytes   BLOB NOT NULL,
			source_peer_id  TEXT NOT NULL,
			created_at      INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (invitee_peer_id, group_id)
		);`,

		// Phase 6: invitee-side pending invite lifecycle for product UI.
		// stored_welcomes is replica storage; this table is local UI state.
		`CREATE TABLE IF NOT EXISTS pending_invites (
			id              TEXT PRIMARY KEY,
			group_id        TEXT NOT NULL,
			group_type      TEXT NOT NULL DEFAULT 'channel',
			group_name      TEXT NOT NULL DEFAULT '',
			inviter_peer_id TEXT NOT NULL DEFAULT '',
			welcome_hash    BLOB NOT NULL,
			welcome_bytes   BLOB NOT NULL,
			source_peer_id  TEXT NOT NULL DEFAULT '',
			status          TEXT NOT NULL DEFAULT 'pending',
			received_at     INTEGER NOT NULL,
			updated_at      INTEGER NOT NULL,
			UNIQUE(group_id, welcome_hash)
		);`,
		`CREATE INDEX IF NOT EXISTS idx_pending_invites_status_received
			ON pending_invites(status, received_at);`,
		`CREATE TABLE IF NOT EXISTS group_invite_requests (
			request_id             TEXT PRIMARY KEY,
			group_id               TEXT NOT NULL,
			requester_peer_id      TEXT NOT NULL,
			target_peer_id         TEXT NOT NULL,
			status                 TEXT NOT NULL,
			failure_code           TEXT NOT NULL DEFAULT '',
			failure_message        TEXT NOT NULL DEFAULT '',
			rejection_reason       TEXT NOT NULL DEFAULT '',
			attempt_count          INTEGER NOT NULL DEFAULT 0,
			max_attempts           INTEGER NOT NULL DEFAULT 5,
			processing_started_at  INTEGER,
			expires_at             INTEGER NOT NULL,
			created_at             INTEGER NOT NULL,
			updated_at             INTEGER NOT NULL,
			is_mirror              INTEGER NOT NULL DEFAULT 0,
			FOREIGN KEY (group_id) REFERENCES mls_groups(group_id) ON DELETE CASCADE
		);`,
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_group_invite_requests_active_unique
			ON group_invite_requests(group_id, target_peer_id)
			WHERE (status = 'pending' OR status = 'processing');`,
		`CREATE INDEX IF NOT EXISTS idx_group_invite_requests_group_status_created
			ON group_invite_requests(group_id, status, created_at);`,
		`CREATE INDEX IF NOT EXISTS idx_group_invite_requests_processing_watchdog
			ON group_invite_requests(status, processing_started_at);`,
		`CREATE INDEX IF NOT EXISTS idx_group_invite_requests_expiry
			ON group_invite_requests(status, expires_at);`,
		`CREATE TABLE IF NOT EXISTS applied_welcomes (
			welcome_fingerprint TEXT PRIMARY KEY,
			group_id            TEXT NOT NULL,
			applied_at          INTEGER NOT NULL
		);`,
		`CREATE INDEX IF NOT EXISTS idx_applied_welcomes_group_applied_at
			ON applied_welcomes(group_id, applied_at);`,
		`CREATE TABLE IF NOT EXISTS admin_issuance_history (
			id             TEXT PRIMARY KEY,
			display_name   TEXT NOT NULL,
			peer_id        TEXT NOT NULL,
			public_key_hex TEXT NOT NULL,
			issued_at      INTEGER NOT NULL,
			expires_at     INTEGER NOT NULL,
			note           TEXT NOT NULL DEFAULT '',
			bundle_path    TEXT NOT NULL DEFAULT ''
		);`,
		`CREATE INDEX IF NOT EXISTS idx_admin_issuance_history_issued_at
			ON admin_issuance_history(issued_at DESC);`,
		`CREATE TABLE IF NOT EXISTS runtime_event_log (
			seq          INTEGER PRIMARY KEY AUTOINCREMENT,
			topic        TEXT    NOT NULL,
			aggregate    TEXT    NOT NULL,
			aggregate_id TEXT    NOT NULL DEFAULT '',
			revision     INTEGER NOT NULL,
			payload_json BLOB    NOT NULL,
			created_at   INTEGER NOT NULL
		);`,
		`CREATE INDEX IF NOT EXISTS idx_runtime_event_log_seq ON runtime_event_log(seq);`,
		`CREATE INDEX IF NOT EXISTS idx_runtime_event_log_aggregate_rev ON runtime_event_log(aggregate, revision);`,
		`CREATE TABLE IF NOT EXISTS group_event_log (
			id             INTEGER PRIMARY KEY AUTOINCREMENT,
			group_id       TEXT    NOT NULL,
			event_type     TEXT    NOT NULL,
			actor_peer_id  TEXT    NOT NULL DEFAULT '',
			target_peer_id TEXT    NOT NULL DEFAULT '',
			epoch          INTEGER NOT NULL DEFAULT 0,
			payload_json   BLOB    NOT NULL,
			created_at_ms  INTEGER NOT NULL
		);`,
		`CREATE INDEX IF NOT EXISTS idx_group_event_log_group_created
			ON group_event_log(group_id, created_at_ms DESC, id DESC);`,
		`CREATE INDEX IF NOT EXISTS idx_group_event_log_group_type
			ON group_event_log(group_id, event_type, created_at_ms DESC, id DESC);`,
		`CREATE TABLE IF NOT EXISTS fork_heal_events (
			id                        INTEGER PRIMARY KEY AUTOINCREMENT,
			trace_id                  TEXT    NOT NULL,
			group_id                  TEXT    NOT NULL,
			winner_peer_id            TEXT    NOT NULL DEFAULT '',
			winner_epoch              INTEGER NOT NULL DEFAULT 0,
			new_epoch                 INTEGER NOT NULL DEFAULT 0,
			outcome                   TEXT    NOT NULL,
			failed_step               TEXT    NOT NULL DEFAULT '',
			winner_tree_hash          BLOB,
			new_tree_hash             BLOB,
			partition_started_at_ms   INTEGER NOT NULL DEFAULT 0,
			scheduled_at_ms           INTEGER NOT NULL DEFAULT 0,
			started_at_ms             INTEGER NOT NULL DEFAULT 0,
			completed_at_ms           INTEGER NOT NULL DEFAULT 0,
			duration_ms               INTEGER NOT NULL DEFAULT 0,
			total_ms                  INTEGER NOT NULL DEFAULT 0,
			replayed_message_count    INTEGER NOT NULL DEFAULT 0,
			created_at                INTEGER NOT NULL DEFAULT (strftime('%s','now'))
		);`,
		`CREATE INDEX IF NOT EXISTS idx_fork_heal_events_group_created
			ON fork_heal_events(group_id, created_at DESC, id DESC);`,
		`CREATE INDEX IF NOT EXISTS idx_fork_heal_events_trace
			ON fork_heal_events(trace_id);`,
		`CREATE TABLE IF NOT EXISTS fork_audit (
			id           INTEGER PRIMARY KEY AUTOINCREMENT,
			trace_id     TEXT    NOT NULL,
			group_id     TEXT    NOT NULL,
			step         TEXT    NOT NULL,
			status       TEXT    NOT NULL,
			ts_ms        INTEGER NOT NULL DEFAULT 0,
			duration_ms  INTEGER NOT NULL DEFAULT 0,
			error        TEXT    NOT NULL DEFAULT '',
			created_at   INTEGER NOT NULL DEFAULT (strftime('%s','now'))
		);`,
		`CREATE INDEX IF NOT EXISTS idx_fork_audit_trace_id
			ON fork_audit(trace_id, id ASC);`,
		`CREATE INDEX IF NOT EXISTS idx_fork_audit_group_created
			ON fork_audit(group_id, created_at DESC, id DESC);`,
		`CREATE TABLE IF NOT EXISTS file_transfers (
			file_id           TEXT PRIMARY KEY,
			group_id          TEXT    NOT NULL,
			direction         TEXT    NOT NULL,
			plaintext_sha256  BLOB    NOT NULL,
			plaintext_size    INTEGER NOT NULL,
			chunk_size        INTEGER NOT NULL,
			chunk_count       INTEGER NOT NULL,
			export_epoch      INTEGER NOT NULL,
			sender_peer_id    TEXT    NOT NULL DEFAULT '',
			ciphertext_dir    TEXT    NOT NULL,
			plaintext_path    TEXT    NOT NULL DEFAULT '',
			state             TEXT    NOT NULL,
			created_at        INTEGER NOT NULL,
			updated_at        INTEGER NOT NULL
		);`,
		`CREATE INDEX IF NOT EXISTS idx_file_transfers_group ON file_transfers(group_id);`,

		// group_add_operations — lifecycle tracker for MLS Add operations.
		//
		// The Single-Writer Protocol separates business-level approval (handled
		// in group_invite_requests) from MLS commit authority (which can rotate
		// to any active member via argmin H(nodeID||epoch)). Approver and
		// Token Holder may be different nodes; the proposal-broadcast flow
		// gives commit authority to whichever node currently holds the token.
		//
		// This row tracks the full coordination lifecycle so every node has a
		// durable, idempotent record that survives restart and lets the
		// runtime recover Welcome delivery if the Token Holder process exits
		// after running CreateCommit but before the invitee acked the join.
		//
		// Status flow:
		//   approved -> proposal_broadcast -> commit_observed -> welcome_queued
		//             -> welcome_delivered (terminal success)
		//   any -> failed (terminal failure)
		//
		// Idempotency: (group_id, target_peer_id, key_package_hash) is unique
		// for any active operation so duplicate approvals/restarts reuse the
		// same row instead of forking lifecycle.
		`CREATE TABLE IF NOT EXISTS group_add_operations (
			operation_id        TEXT PRIMARY KEY,
			request_id          TEXT NOT NULL DEFAULT '',
			group_id            TEXT NOT NULL,
			target_peer_id      TEXT NOT NULL,
			requester_peer_id   TEXT NOT NULL DEFAULT '',
			approver_peer_id    TEXT NOT NULL DEFAULT '',
			key_package_hash    TEXT NOT NULL,
			proposal_epoch      INTEGER,
			commit_epoch        INTEGER,
			commit_hash         BLOB,
			welcome_hash        TEXT NOT NULL DEFAULT '',
			status              TEXT NOT NULL,
			failure_code        TEXT NOT NULL DEFAULT '',
			failure_message     TEXT NOT NULL DEFAULT '',
			created_at          INTEGER NOT NULL,
			updated_at          INTEGER NOT NULL,
			last_attempt_at     INTEGER NOT NULL DEFAULT 0,
			FOREIGN KEY (group_id) REFERENCES mls_groups(group_id) ON DELETE CASCADE
		);`,
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_group_add_operations_active_unique
			ON group_add_operations(group_id, target_peer_id, key_package_hash)
			WHERE (status != 'failed' AND status != 'welcome_delivered');`,
		`CREATE INDEX IF NOT EXISTS idx_group_add_operations_status
			ON group_add_operations(group_id, status, updated_at);`,
		`CREATE INDEX IF NOT EXISTS idx_group_add_operations_recoverable
			ON group_add_operations(status, updated_at);`,

		// replicated_records — generic signed replicated object rows (namespace + key).
		`CREATE TABLE IF NOT EXISTS replicated_records (
			namespace               TEXT    NOT NULL,
			record_key              TEXT    NOT NULL,
			owner_peer_id           TEXT    NOT NULL,
			revision                INTEGER NOT NULL,
			schema_version          INTEGER NOT NULL DEFAULT 1,
			body_json               TEXT    NOT NULL,
			body_hash               TEXT    NOT NULL,
			signature               BLOB    NOT NULL,
			signing_public_key_hex  TEXT    NOT NULL,
			deleted_at              INTEGER NOT NULL DEFAULT 0,
			updated_at              INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (namespace, record_key)
		);`,
		`CREATE INDEX IF NOT EXISTS idx_replicated_records_owner
			ON replicated_records(owner_peer_id, namespace, revision DESC);`,

		// replicated_pull_state — per-remote cursor for incremental replica-store pulls.
		`CREATE TABLE IF NOT EXISTS replicated_pull_state (
			remote_peer_id   TEXT    NOT NULL,
			namespace        TEXT    NOT NULL,
			record_key       TEXT    NOT NULL,
			last_revision    INTEGER NOT NULL DEFAULT 0,
			updated_at       INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (remote_peer_id, namespace, record_key)
		);`,

		// replicated_blobs — content-addressed blobs for replicated objects (non-avatar types later).
		`CREATE TABLE IF NOT EXISTS replicated_blobs (
			hash          TEXT PRIMARY KEY,
			mime          TEXT    NOT NULL,
			size          INTEGER NOT NULL,
			bytes         BLOB    NOT NULL,
			created_at    INTEGER NOT NULL,
			last_used_at  INTEGER NOT NULL
		);`,
		`CREATE TABLE IF NOT EXISTS replicated_record_blobs (
			namespace   TEXT    NOT NULL,
			record_key  TEXT    NOT NULL,
			blob_hash   TEXT    NOT NULL,
			required    INTEGER NOT NULL DEFAULT 1,
			created_at  INTEGER NOT NULL DEFAULT (strftime('%s','now')),
			PRIMARY KEY (namespace, record_key, blob_hash),
			FOREIGN KEY (namespace, record_key)
				REFERENCES replicated_records(namespace, record_key)
				ON DELETE CASCADE
		);`,
		`CREATE INDEX IF NOT EXISTS idx_replicated_record_blobs_hash
			ON replicated_record_blobs(blob_hash);`,

		// Notifications for the Activity Tab.
		`CREATE TABLE IF NOT EXISTS notifications (
			id             TEXT PRIMARY KEY,
			type           TEXT    NOT NULL,
			group_id       TEXT    NOT NULL,
			actor_peer_id  TEXT    NOT NULL,
			target_id      TEXT    NOT NULL,
			content        TEXT,
			is_read        BOOLEAN NOT NULL DEFAULT 0,
			created_at     DATETIME DEFAULT CURRENT_TIMESTAMP
		);`,
		`CREATE INDEX IF NOT EXISTS idx_notifications_is_read ON notifications(is_read);`,
		`CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON notifications(created_at DESC);`,
		`CREATE TABLE IF NOT EXISTS pending_operation (
			operation_id            TEXT PRIMARY KEY,
			group_id                TEXT NOT NULL,
			op_type                 TEXT NOT NULL,
			idempotency_key         TEXT,
			operation_hash          BLOB,
			precondition_epoch      INTEGER,
			precondition_state_hash  BLOB,
			target_member_id        TEXT,
			semantic_payload        BLOB NOT NULL,
			latest_proposal_hash    BLOB,
			status                  TEXT NOT NULL,
			retry_count             INTEGER DEFAULT 0,
			expires_at              INTEGER,
			last_error              TEXT,
			created_at              INTEGER NOT NULL,
			updated_at              INTEGER NOT NULL
		);`,
		// Partial unique index: only enforce idempotency for active (non-terminal) operations.
		// This allows a new ADD_MEMBER for the same peer after a previous one is COMMITTED,
		// SATISFIED_BY_OTHER, FAILED_*, etc — e.g. add Dave, remove Dave, add Dave again.
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_op_idempotency_active ON pending_operation(group_id, idempotency_key)
		 WHERE idempotency_key IS NOT NULL AND status IN ('PENDING','PROPOSED');`,

		// Milestone 5: Crash-safe fork healing state machine tracking.
		`CREATE TABLE IF NOT EXISTS fork_healing_job (
			job_id                   TEXT PRIMARY KEY,
			group_id                 TEXT NOT NULL,
			trace_id                 TEXT NOT NULL,
			status                   TEXT NOT NULL,
			losing_branch_id         TEXT NOT NULL,
			winning_branch_id        TEXT NOT NULL,
			fork_base_epoch          INTEGER,
			losing_epoch             INTEGER NOT NULL,
			winning_epoch            INTEGER NOT NULL,
			losing_tree_hash         BLOB,
			winning_tree_hash        BLOB NOT NULL,
			winning_commit_hash      BLOB,
			winning_group_info_hash  BLOB,
			winner_peer_id           TEXT NOT NULL,
			winner_group_info        BLOB,
			branch_weight_json       TEXT,
			pending_group_state      BLOB,
			pending_epoch            INTEGER,
			pending_tree_hash        BLOB,
			error_message            TEXT,
			retry_count              INTEGER DEFAULT 0,
			created_at_ms            INTEGER NOT NULL,
			updated_at_ms            INTEGER NOT NULL,
			completed_at_ms          INTEGER
		);`,
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_fork_healing_active_group ON fork_healing_job(group_id)
		 WHERE status NOT IN ('CLEANED', 'FAILED_TERMINAL');`,

		// Milestone 5: Losing branch envelope snapshots and plaintexts prior to key shredding.
		`CREATE TABLE IF NOT EXISTS application_event (
			event_id               TEXT PRIMARY KEY,
			job_id                 TEXT NOT NULL,
			group_id               TEXT NOT NULL,
			original_branch_id     TEXT NOT NULL,
			original_epoch         INTEGER NOT NULL,
			author_id              TEXT NOT NULL,
			envelope_hash          BLOB NOT NULL,
			payload_sealed         BLOB,
			payload_hash           BLOB NOT NULL,
			seal_key_id            TEXT,
			seal_nonce             BLOB,
			hlc_wall_time_ms       INTEGER NOT NULL,
			hlc_counter            INTEGER NOT NULL,
			hlc_node_id            TEXT NOT NULL,
			status                 TEXT NOT NULL,
			replay_operation_id    TEXT,
			replayed_envelope_hash BLOB,
			replayed_at_ms         INTEGER,
			replay_attempt_count   INTEGER DEFAULT 0,
			last_error             TEXT,
			created_at_ms          INTEGER NOT NULL,
			updated_at_ms          INTEGER NOT NULL
		);`,
		`CREATE TABLE IF NOT EXISTS outbound_replay_queue (
			replay_operation_id     TEXT PRIMARY KEY,
			event_id                TEXT NOT NULL,
			job_id                  TEXT NOT NULL,
			group_id                TEXT NOT NULL,
			replay_envelope         BLOB NOT NULL,
			replayed_envelope_hash  BLOB NOT NULL,
			status                  TEXT NOT NULL,
			attempt_count           INTEGER DEFAULT 0,
			created_at_ms           INTEGER NOT NULL,
			updated_at_ms           INTEGER NOT NULL
		);`,
		`CREATE INDEX IF NOT EXISTS idx_application_event_group ON application_event(group_id);`,
		`CREATE INDEX IF NOT EXISTS idx_application_event_job_status ON application_event(job_id, status);`,
	}

	for _, q := range queries {
		if _, err := d.Conn.Exec(q); err != nil {
			return fmt.Errorf("failed to create table: %w", err)
		}
	}
	if err := d.ensureColumnExists("stored_messages", "envelope_hash", "BLOB"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("stored_messages", "replayed_at", "INTEGER"); err != nil {
		return err
	}
	for _, col := range []struct {
		name string
		typ  string
	}{
		{"envelope_hash", "BLOB"},
		{"source_path", "TEXT NOT NULL DEFAULT 'local'"},
		{"apply_state", "TEXT NOT NULL DEFAULT 'pending'"},
		{"last_apply_error", "TEXT NOT NULL DEFAULT ''"},
		{"last_apply_attempt_at", "INTEGER NOT NULL DEFAULT 0"},
		{"applied_at", "INTEGER NOT NULL DEFAULT 0"},
		{"first_seen_at_ms", "INTEGER NOT NULL DEFAULT 0"},
		{"received_at_ms", "INTEGER NOT NULL DEFAULT 0"},
	} {
		if err := d.ensureColumnExists("envelope_log", col.name, col.typ); err != nil {
			return err
		}
	}
	if err := d.backfillEnvelopeLogHashes(); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "lifecycle_status", "TEXT NOT NULL DEFAULT 'active'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "left_at", "INTEGER NOT NULL DEFAULT 0"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "group_type", "TEXT NOT NULL DEFAULT 'channel'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "dm_counterparty_peer_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "group_creator_peer_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "category_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "invite_policy", "TEXT NOT NULL DEFAULT 'creator_approval'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "group_avatar_hash", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "group_avatar_mime", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("mls_groups", "group_avatar_updated_at", "INTEGER NOT NULL DEFAULT 0"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("coordination_state", "history_chain", "TEXT NOT NULL DEFAULT '{}'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("pending_welcomes_out", "anchor_epoch", "INTEGER NOT NULL DEFAULT 0"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("pending_welcomes_out", "anchor_history_hash", "BLOB"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("stored_welcomes", "group_type", "TEXT NOT NULL DEFAULT 'channel'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("stored_welcomes", "category_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("stored_welcomes", "anchor_epoch", "INTEGER NOT NULL DEFAULT 0"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("stored_welcomes", "anchor_history_hash", "BLOB"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("pending_invites", "group_type", "TEXT NOT NULL DEFAULT 'channel'"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("pending_invites", "category_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("group_invite_requests", "is_mirror", "INTEGER NOT NULL DEFAULT 0"); err != nil {
		return err
	}
	// add_operation_id links an invite request row to its MLS coordination
	// lifecycle (group_add_operations). Empty string means "not yet linked"
	// (legacy rows, pending creator approval, or rejected requests).
	if err := d.ensureColumnExists("group_invite_requests", "add_operation_id", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	// public_key_hex extends peer_directory with the verified MLS signing
	// public key (hex-encoded) the peer presented in its InvitationToken.
	// Used by joinGroupWithWelcome's MLS leaf enumeration to resolve each
	// leaf's BasicCredential identity back to a peer.ID — without it, only
	// the welcome-source and message senders would land in group_members.
	// Empty string ("") means we have not yet observed the peer's verified
	// pubkey (legacy rows, or directory rebuilt before handshake completes).
	if err := d.ensureColumnExists("peer_directory", "public_key_hex", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	if err := d.ensureColumnExists("file_transfers", "plaintext_path", "TEXT NOT NULL DEFAULT ''"); err != nil {
		return err
	}
	for _, col := range []struct {
		table string
		name  string
		typ   string
	}{
		{"local_profile", "email", "TEXT"},
		{"local_profile", "phone", "TEXT"},
		{"local_profile", "avatar_hash", "TEXT"},
		{"local_profile", "avatar_mime", "TEXT"},
		{"local_profile", "avatar_updated_at", "INTEGER NOT NULL DEFAULT 0"},
		{"peer_directory", "email", "TEXT"},
		{"peer_directory", "phone", "TEXT"},
		{"peer_directory", "avatar_hash", "TEXT"},
		{"peer_directory", "avatar_mime", "TEXT"},
		{"peer_directory", "avatar_updated_at", "INTEGER NOT NULL DEFAULT 0"},
		{"peer_directory", "profile_revision", "INTEGER NOT NULL DEFAULT 0"},
		{"peer_directory", "profile_signature", "TEXT"},
	} {
		if err := d.ensureColumnExists(col.table, col.name, col.typ); err != nil {
			return err
		}
	}
	if _, err := d.Conn.Exec(
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_stored_messages_group_envelope_hash
		 ON stored_messages(group_id, envelope_hash)
		 WHERE envelope_hash IS NOT NULL`,
	); err != nil {
		return fmt.Errorf("create stored_messages envelope_hash index: %w", err)
	}
	if _, err := d.Conn.Exec(
		`CREATE INDEX IF NOT EXISTS idx_stored_messages_sender_window
		 ON stored_messages(group_id, sender_id, hlc_wall_time_ms)`,
	); err != nil {
		return fmt.Errorf("create stored_messages sender_window index: %w", err)
	}
	if _, err := d.Conn.Exec(
		`CREATE INDEX IF NOT EXISTS idx_envelope_log_group_apply_seq
		 ON envelope_log(group_id, apply_state, seq)`,
	); err != nil {
		return fmt.Errorf("create envelope_log apply index: %w", err)
	}
	if _, err := d.Conn.Exec(
		`CREATE INDEX IF NOT EXISTS idx_envelope_log_group_hash
		 ON envelope_log(group_id, envelope_hash)`,
	); err != nil {
		return fmt.Errorf("create envelope_log hash index: %w", err)
	}
	if _, err := d.Conn.Exec(
		`CREATE INDEX IF NOT EXISTS idx_mls_groups_type_category
		 ON mls_groups(group_type, category_id)
		 WHERE lifecycle_status = 'active'`,
	); err != nil {
		return fmt.Errorf("create mls_groups type_category index: %w", err)
	}
	// Migration: drop the old broad idempotency index (covers all statuses) if it exists,
	// replaced by the narrower idx_op_idempotency_active covering only PENDING/PROPOSED.
	if _, err := d.Conn.Exec(`DROP INDEX IF EXISTS idx_op_idempotency`); err != nil {
		return fmt.Errorf("drop legacy idx_op_idempotency: %w", err)
	}
	return nil
}

func (d *Database) backfillEnvelopeLogHashes() error {
	rows, err := d.Conn.Query(`SELECT id, envelope FROM envelope_log WHERE envelope_hash IS NULL OR length(envelope_hash) = 0`)
	if err != nil {
		return fmt.Errorf("select envelope hashes: %w", err)
	}
	defer rows.Close()

	type row struct {
		id       int64
		envelope []byte
	}
	var missing []row
	for rows.Next() {
		var r row
		if err := rows.Scan(&r.id, &r.envelope); err != nil {
			return fmt.Errorf("scan envelope hash row: %w", err)
		}
		missing = append(missing, r)
	}
	if err := rows.Err(); err != nil {
		return fmt.Errorf("iterate envelope hash rows: %w", err)
	}
	for _, r := range missing {
		sum := sha256.Sum256(r.envelope)
		if _, err := d.Conn.Exec(`UPDATE envelope_log SET envelope_hash = ? WHERE id = ?`, sum[:], r.id); err != nil {
			return fmt.Errorf("backfill envelope hash: %w", err)
		}
	}
	return nil
}

func (d *Database) ensureColumnExists(tableName, columnName, columnType string) error {
	rows, err := d.Conn.Query(fmt.Sprintf(`PRAGMA table_info(%s)`, tableName))
	if err != nil {
		return fmt.Errorf("table info %s: %w", tableName, err)
	}
	defer rows.Close()

	for rows.Next() {
		var (
			cid        int
			name       string
			typ        string
			notNull    int
			defaultV   sql.NullString
			primaryKey int
		)
		if err := rows.Scan(&cid, &name, &typ, &notNull, &defaultV, &primaryKey); err != nil {
			return fmt.Errorf("scan table info %s: %w", tableName, err)
		}
		if strings.EqualFold(name, columnName) {
			return nil
		}
	}
	if err := rows.Err(); err != nil {
		return fmt.Errorf("iterate table info %s: %w", tableName, err)
	}

	if _, err := d.Conn.Exec(fmt.Sprintf(`ALTER TABLE %s ADD COLUMN %s %s`, tableName, columnName, columnType)); err != nil {
		return fmt.Errorf("add column %s.%s: %w", tableName, columnName, err)
	}
	return nil
}

func (d *Database) Close() {
	if d.Conn != nil {
		d.Conn.Close()
	}
}
